layout_algorithm.index_to_center_js:
// Vanilla JS. row 0 = TOP, row (ROWS-1)=3 = BOTTOM. The SNAKE starts at the
// BOTTOM row and climbs, so we map snake-index i -> visual (row,col) with the
// bottom row first and a serpentine flip.
function nodeCenter(i) {
  const ROWS=4, COLS=6, MX=96, MY=78, CP=128, RP=180;
  // snakeRow 0 = bottom (start), snakeRow 3 = top (exit)
  const snakeRow = Math.floor(i / COLS);              // 0..3
  const idxInRow = i % COLS;                            // 0..5
  // bottom row (snakeRow 0) travels RIGHT->LEFT; alternate each row up.
  // 'forward' here means left->right in screen space.
  const goLeftToRight = (snakeRow % 2 === 1);          // row0 R->L, row1 L->R, ...
  const col = goLeftToRight ? idxInRow : (COLS - 1 - idxInRow);
  const visualRow = (ROWS - 1) - snakeRow;             // bottom row -> visualRow 3
  const cx = MX + col * CP;                            // 96 .. 736
  const cy = MY + visualRow * RP;                      // 78,258? -> use MY + row*RP = 78,258... 
  // NOTE: with MY=78 and RP=180 the four row centers are y = 78, 258, 438, 618.
  // 618 overflows 560. So clamp the band: we actually want y = {78,178? }.
  // CANONICAL row-y table (kept explicit so it never drifts):
  const ROW_Y = [78, 178, 298, 478];                   // top..bottom (visualRow 0..3)
  return { cx, cy: ROW_Y[visualRow] };
}
// The waypoint polyline = NODES.map((_,i)=>nodeCenter(i)). Avatars animate node->node.
// ROW_Y is non-uniform on purpose: tighter at top (small tiles), roomier at bottom
// where START/HAZARD carry more text. Tune ROW_Y, never the formula.

avatar_anim.climb_tween_js:
// One transform transition PER square climbed, queued, so a spin of 4 reads as
// four discrete hops (not a blur). Reuse the .board-cat curve already in css.
async function climb(token, fromIndex, steps) {
  for (let s = 1; s <= steps; s++) {
    const i = fromIndex + s;
    const { cx, cy } = NODES[i];           // single source of truth
    const yAnchor = token.dataset.role === 'cat' ? cy - 56 : cy + 56;
    token.style.transition = 'transform .18s cubic-bezier(.2,.8,.2,1)';
    token.style.transform = `translate(${cx}px, ${yAnchor}px)`;
    token.classList.add('hop');            // CSS @keyframes comic bounce
    await wait(180);
    token.classList.remove('hop');
    burnCapital(CAPITAL_PER_STEP);         // each hop burns fuel (HUD)
    spawnCapitalChip(cx, yAnchor);         // '-$Xm' floats up & fades
  }
}

spinner_widget.spin_js:
// Only the .needle <g> rotates (transform-only, GPU-friendly). 1-4 is uniform
// random; the needle lands on the matching quadrant CENTER + jitter.
function spin() {
  const result = 1 + Math.floor(Math.random() * 4);     // 1..4
  // quadrant centers: 1=-45deg-ish; map result->target angle so the needle
  // points into the right wedge. q angles (needle 0=up): 4 -> -45, 1 -> 45,
  // 2 -> 135, 3 -> 225 (wedge centers). Add 3-4 full spins for drama.
  const wedge = { 1: 45, 2: 135, 3: 225, 4: 315 }[result];
  const spins = 3 + Math.floor(Math.random() * 2);       // 3..4 turns
  const target = spins * 360 + wedge + (Math.random()*20 - 10);
  const needle = document.querySelector('.spinner .needle');
  needle.style.transition = 'transform 1.1s cubic-bezier(.15,.85,.2,1)';
  needle.style.transform = `rotate(${target}deg)`;
  playTick();                                            // Web-Audio ratchet
  return new Promise(res => setTimeout(() => res(result), 1150));
}
